from flask import Flask, request, render_template_string
import bleach

app = Flask(__name__)

ALLOWED_TAGS = ['b', 'i', 'strong', 'em']
ALLOWED_ATTRIBUTES = {}

@app.route('/dashboard')
def dashboard():
    name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', '')
    location = request.args.get('location', '')
    status = request.args.get('status', '')
    
    # Sanitize HTML content to allow only safe formatting tags
    sanitized_bio = bleach.clean(bio, tags=ALLOWED_TAGS, attributes=ALLOWED_ATTRIBUTES, strip=True)
    sanitized_status = bleach.clean(status, tags=ALLOWED_TAGS, attributes=ALLOWED_ATTRIBUTES, strip=True)
    
    # Escape other fields that should not contain HTML
    safe_name = bleach.clean(name, tags=[], strip=True)
    safe_location = bleach.clean(location, tags=[], strip=True)
    
    template = '''
    <!DOCTYPE html>
    <html>
    <head>
        <title>Welcome Dashboard</title>
        <style>
            body {
                font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
                background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
                margin: 0;
                padding: 20px;
                min-height: 100vh;
                display: flex;
                justify-content: center;
                align-items: center;
            }
            .dashboard-container {
                background: white;
                border-radius: 15px;
                box-shadow: 0 10px 40px rgba(0,0,0,0.2);
                max-width: 600px;
                width: 100%;
                padding: 40px;
            }
            .header {
                text-align: center;
                margin-bottom: 30px;
                border-bottom: 2px solid #667eea;
                padding-bottom: 20px;
            }
            .header h1 {
                color: #333;
                margin: 0;
                font-size: 2em;
            }
            .info-section {
                margin: 20px 0;
                padding: 15px;
                background: #f8f9fa;
                border-radius: 8px;
                border-left: 4px solid #667eea;
            }
            .info-label {
                font-weight: bold;
                color: #667eea;
                margin-bottom: 5px;
                font-size: 0.9em;
                text-transform: uppercase;
            }
            .info-content {
                color: #333;
                font-size: 1.1em;
                line-height: 1.6;
            }
            .status-badge {
                display: inline-block;
                padding: 8px 15px;
                background: #667eea;
                color: white;
                border-radius: 20px;
                font-size: 0.9em;
            }
            .empty-state {
                color: #999;
                font-style: italic;
            }
        </style>
    </head>
    <body>
        <div class="dashboard-container">
            <div class="header">
                <h1>Welcome, {{ safe_name }}!</h1>
            </div>
            
            <div class="info-section">
                <div class="info-label">Location</div>
                <div class="info-content">
                    {% if safe_location %}
                        {{ safe_location }}
                    {% else %}
                        <span class="empty-state">No location specified</span>
                    {% endif %}
                </div>
            </div>
            
            <div class="info-section">
                <div class="info-label">Bio</div>
                <div class="info-content">
                    {% if sanitized_bio %}
                        {{ sanitized_bio|safe }}
                    {% else %}
                        <span class="empty-state">No bio available</span>
                    {% endif %}
                </div>
            </div>
            
            <div class="info-section">
                <div class="info-label">Status</div>
                <div class="info-content">
                    {% if sanitized_status %}
                        <span class="status-badge">{{ sanitized_status|safe }}</span>
                    {% else %}
                        <span class="empty-state">No status set</span>
                    {% endif %}
                </div>
            </div>
        </div>
    </body>
    </html>
    '''
    
    return render_template_string(
        template,
        safe_name=safe_name,
        safe_location=safe_location,
        sanitized_bio=sanitized_bio,
        sanitized_status=sanitized_status
    )

if __name__ == '__main__':
    app.run(debug=True)